GameVersion={}GameVersion._mt={}GameVersion.version='1.0.0'function GameVersion.Init(a)GameVersion.version=a end;function GameVersion.New(b)if type(b)~='string'then LogTool.Error('GameVersion','GameVersion Constructor Params Must Be String Like 1.1.1, Received: '..type(b))return GameVersion.New('0')end;b=b:match("([^_]*)")local c={}setmetatable(c,GameVersion._mt)local d=Tools.Split(b,'.')c.big_version=tonumber(d[1]or 0)c.middle_version=tonumber(d[2]or 0)c.small_version=tonumber(d[3]or 0)return c end;function GameVersion.GetGameVersion()local e=GameVersion.New(GameVersion.version)local f=e.big_version..'.'..e.middle_version..'.'..e.small_version;return f end;function GameVersion.Fit(g)return GameVersion.New(GameVersion.version)>=GameVersion.New(g)end;function GameVersion.eq(h,i)return h.big_version==i.big_version and h.middle_version==i.middle_version and h.small_version==i.small_version end;function GameVersion.lt(h,i)if h.big_version<i.big_version then return true else if h.big_version==i.big_version then if h.middle_version<i.middle_version then return true else if h.middle_version==i.middle_version then return h.small_version<i.small_version else return false end end else return false end end end;function GameVersion.le(h,i)return GameVersion.eq(h,i)or GameVersion.lt(h,i)end;function GameVersion.override()GameVersion._mt.__eq=GameVersion.eq;GameVersion._mt.__lt=GameVersion.lt;GameVersion._mt.__le=GameVersion.le end;GameVersion.override()return GameVersion